('ph-bi-foundations', NULL, 100, 'phase', NULL, NULL, NULL, 'BI Foundations and Business Context', 'Build the business intelligence mindset, analytics vocabulary, stakeholder focus, and decision-support context required for BI work.', 'trunk', 14, 'beginner', '{"source": "roadmap.sh/bi-analyst", "visualRule": "main_spine"}'::jsonb, true, false, '["Explain the purpose of the BI Foundations and Business Context phase and its role in the full business intelligence path.", "Connect the phase topics to concrete business intelligence deliverables.", "Identify the artifacts or evidence needed before progressing."]'::jsonb, '["Summarize the key concepts covered in BI Foundations and Business Context.", "Identify completed and incomplete child topics or projects.", "Prepare notes or artifacts that show readiness for the next phase."]'::jsonb),
