('chk-bi-foundations-review', 'ph-bi-foundations', 180, 'checkpoint', 'assessment', NULL, NULL, 'BI Foundations Review Gate', 'Practical checkpoint for BI Foundations and Business Context. The learner completes a small diagnostic task or review artifact using BI Analyst Role and Responsibilities, Business Intelligence vs Analytics, Analytics Lifecycle, Data-Driven Decision Making and records observations that can guide further practice.', 'checkpoint', 2, 'beginner', '{"gateFor": "ph-bi-foundations", "source": "roadmap.sh/bi-analyst", "checkpointPurpose": "phase_review", "reviewMode": "assessment", "evidenceRequired": true, "claimLimit": "orientation_and_progress_review_only_not_certification"}'::jsonb, true, true, '["Apply selected concepts from BI Foundations and Business Context to a small practical scenario.", "Explain what worked, what failed, and which signals were used to debug or validate the result.", "Translate the result into a short next-action plan for continued learning."]'::jsonb, '["Complete a small practical task, lab, review exercise, or worked example related to this segment.", "Attach or describe the output, result, or evidence used for review.", "Explain at least one mistake, trade-off, or failure mode encountered during the task.", "Write the next practice action based on the result."]'::jsonb),
('proj-kpi-brief', 'ph-bi-foundations', 190, 'project', NULL, NULL, NULL, 'Required KPI Brief for a Business Scenario', 'Milestone project: Create a KPI brief for a sample business problem with stakeholders, metric definitions, grain, data sources, risks, and decision actions.', 'side', 4, 'beginner', '{"project":true,"projectBrief":"Create a KPI brief for a sample business problem with stakeholders, metric definitions, grain, data sources, risks, and decision actions.","projectKind":"analytics_artifact","projectScope":"focused_milestone","projectPurpose":"Demonstrate the surrounding roadmap segment through a focused milestone artifact.","phaseContext":"BI Foundations and Business Context","deliverable":"a KPI Brief for a Business Scenario workbook, report, or dashboard with documented assumptions","skillsToPractice":["BI Foundations and Business Context"],"suggestedSteps":["Define the KPI Brief for a Business Scenario scenario and list the specific items to demonstrate: KPI definitions.","Define the business question, audience, grain, metric formulas, and decision the artifact should support.","Prepare or clean the dataset and document assumptions, exclusions, and data-quality checks.","Build the report, dashboard, notebook, or workbook with the minimum views needed to answer the question.","Validate the numbers against source rows, spot checks, or reconciliation notes.","Write a short interpretation with caveats and recommended next actions.","Keep the scope focused enough to complete, review, and explain the a KPI Brief for a Business Scenario workbook, report, or dashboard with documented assumptions."],"expectedEvidence":["a KPI Brief for a Business Scenario workbook, report, or dashboard with documented assumptions.","README or notes that explain setup, usage, assumptions, and expected output.","Metric definitions, charts/tables, source checks, and a concise interpretation for the intended audience.","Validation evidence such as tests, screenshots, logs, query