('grp-interview-readiness', 'ph-portfolio-career', 1420, 'choice_group', NULL, 'complete_all', NULL, 'BI Interview Readiness', 'Group related options around BI Interview Readiness so learners can complete the required selection model without changing the main phase structure.', 'side', 2, 'advanced', '{"selectionType": "complete_all", "source": "roadmap.sh/bi-analyst"}'::jsonb, true, false, '["Compare the options or grouped topics inside BI Interview Readiness.", "Select or complete the required children according to the group rule.", "Explain how the selected work supports practical business intelligence readiness."]'::jsonb, '["Complete the required number of child nodes for this group.", "Document why the selected options fit the learner''s target direction or project needs.", "Confirm that required child projects or topics have reviewable evidence."]'::jsonb),
('sql-interview-practice-bi', 'grp-interview-readiness', 1, 'topic', NULL, NULL, NULL, 'SQL Interview Practice for BI', 'Practice joins, aggregations, window functions, retention, funnels, and metric calculations.', 'side', 3, 'advanced', '{"source": "roadmap.sh/bi-analyst", "parentGroup": "grp-interview-readiness"}'::jsonb, true, true, '["Explain SQL Interview Practice for BI through business question, metric definition, data evidence, and stakeholder communication.", "Apply SQL Interview Practice for BI in a realistic business intelligence task.", "Identify trade-offs, risks, debugging signals, or quality checks related to the topic."]'::jsonb, '["Create or update notes explaining SQL Interview Practice for BI with a concrete example.", "Use the topic to produce a metric note, report sketch, dashboard mockup, or analysis artifact.", "Record at least two decisions, risks, or validation checks that prove applied understanding."]'::jsonb),
('case-interview-for-analytics', 'grp-interview-readiness', 2, 'topic', NULL, NULL, NULL, 'Analytics Case Interviews', 'Solve ambiguous business cases by clarifying goals, defining metrics, asking for data, and recommending action.', 'side', 3, 'advanced', '{"source": "roadmap.sh/bi-analyst", "parentGroup": "grp-interview-readiness"}'::jsonb, true, true, '["Explain Analytics Case Interviews through business question, metric definition, data evidence, and stakeholder communication.", "Apply Analytics Case Interviews in a realistic business intelligence task.", "Identify trade-offs, risks, debugging signals, or quality checks related to the topic."]'::jsonb, '["Create or update notes explaining Analytics Case Interviews with a concrete example.", "Use the topic to produce a metric note, report sketch, dashboard mockup, or analysis artifact.", "Record at least two decisions, risks, or validation checks that prove applied understanding."]'::jsonb),
('dashboard-review-interview', 'grp-interview-readiness', 3, 'topic', NULL, NULL, NULL, 'Dashboard Review Interview', 'Explain dashboard choices, data model, metric definitions, caveats, and stakeholder tradeoffs.', 'side', 2, 'advanced', '{"source": "roadmap.sh/bi-analyst", "parentGroup": "grp-interview-readiness"}'::jsonb, true, true, '["Explain Dashboard Review Interview through business question, metric definition, data evidence, and stakeholder communication.", "Apply Dashboard Review Interview in a realistic business intelligence task.", "Identify trade-offs, risks, debugging signals, or quality checks related to the topic."]'::jsonb, '["Create or update notes explaining Dashboard Review Interview with a concrete example.", "Use the topic to produce a metric note, report sketch, dashboard mockup, or analysis artifact.", "Record at least two decisions, risks, or validation checks that prove applied understanding."]'::jsonb),
('behavioral-interview-bi', 'grp-interview-readiness', 4, 'topic', NULL, NULL, NULL, 'Behavioral Interview for BI', 'Prepare stories about ambiguity, stakeholder conflict, data quality issues, deadlines, and business impact.', 'side', 2, 'advanced', '{"source": "roadmap.sh/bi-analyst", "parentGroup": "grp-interview-readiness"}'::jsonb, true, true, '["Explain Behavioral Interview for BI through business question, metric definition, data evidence, and stakeholder communication.", "Apply Behavioral Interview for BI in a realistic business intelligence task.", "Identify trade-offs, risks, debugging signals, or quality checks related to the topic."]'::jsonb, '["Create or update notes explaining Behavioral Interview for BI with a concrete example.", "Use the topic to produce a metric note, report sketch, dashboard mockup, or analysis artifact.", "Record at least two decisions, risks, or validation checks that prove applied understanding."]'::jsonb),
('chk-final-bi-review', 'ph-portfolio-career', 1480, 'checkpoint', 'gate', NULL, NULL, 'Final BI Roadmap Review Gate', 'Final roadmap checkpoint for Portfolio, Interview Readiness, and Capstone. The learner reviews portfolio evidence, unresolved gaps, and next learning priorities across the business intelligence analysis path.', 'checkpoint', 2, 'advanced', '{"gateFor": "ph-portfolio-career", "source": "roadmap.sh/bi-analyst", "checkpointPurpose": "phase_review", "reviewMode": "final_review", "evidenceRequired": true, "claimLimit": "orientation_and_progress_review_only_not_certification"}'::jsonb, true, true, '["Connect completed roadmap work to a coherent business intelligence analysis learning narrative.", "Review portfolio or project evidence and identify which artifacts are ready to share.", "Define remaining gaps and future specialization priorities."]'::jsonb, '["Summarize completed phases, projects, and major skill groups.", "Attach or reference portfolio evidence, project links, diagrams, reports, tests, or notes where available.", "List remaining gaps or specialization topics for future learning.", "State that the checkpoint is a planning review, not proof of job readiness."]'::jsonb),
('proj-bi-capstone', 'ph-portfolio-career', 1490, 'project', NULL, NULL, NULL, 'Required Business Intelligence Capstone Project', 'Capstone project: Build an end-to-end BI capstone: define business problem, prepare data, model metrics, create dashboard, validate quality, write an insight deck, and present recommendations.', 'side', 10, 'advanced', '{"project":true,"projectBrief":"Build an end-to-end BI capstone: define business problem, prepare data, model metrics, create dashboard, validate quality, write an insight deck, and present recommendations.","projectKind":"portfolio_capstone","projectScope":"portfolio_capstone","projectPurpose":"Integrate several roadmap areas into a portfolio-ready case study.","phaseContext":"Portfolio, Interview Readiness, and Capstone","deliverable":"a portfolio-ready Business Intelligence Capstone Project case study and integrated artifact","skillsToPractice":["Dashboard Design","Business Metrics","Data Storytelling","Portfolio Communication","Career Planning"],"suggestedSteps":["Define the Business Intelligence Capstone Project scenario and list the specific items to demonstrate: dashboard decisions, model behavior and evaluation, metrics.","Choose a coherent product or case-study scenario that can integrate the strongest projects from the roadmap.","Define the architecture, data or workflow model, user path, and review evidence before implementation.","Build the core artifact end-to-end with scoped features rather than disconnected demos.","Add validation evidence appropriate to the role, such as tests, metrics, query checks, playtest notes, traces, screenshots, or incident notes.","Prepare a case study explaining decisions, trade-offs, limitations, and what would need further review for real deployment.","Package the repository or artifact so another person can reproduce or inspect the result.","Create a review checklist that connects the artifact to the relevant skills and roadmap segment.","Write a limitation and risk section so the project is presented as reviewable evidence, not a certification claim."],"expectedEvidence":["a portfolio-ready Business Intelligence Capstone Project case study and integrated artifact.","README or notes that explain setup, usage, assumptions, and expected output.","Case study page or write-up that connects the artifact to role-relevant decisions and evidence.","Validation evidence such as tests, screenshots, logs, query results, metrics, traces, or review notes.","Short reflection on trade-offs, limitations, and one reasonable next improvement.","Architecture, review checklist, and limitation section suitable for portfolio discussion."],"reviewFocus":["Does the artifact directly match the project brief?","Can another person run, inspect, or review the result from the provided notes?","Are assumptions, limitations, and trade-offs stated clearly?"],"scopeGuardrails":["Keep the implementation focused on the stated project brief.","Prefer a complete small artifact over a broad unfinished system.","Treat completion as reviewable evidence, not a certification claim."],"claimLimit":"Completion creates reviewable project evidence. It does not certify mastery or guarantee job readiness.","evidenceRequired":true,"optionalPractice":false,"milestone":true,"source":"roadmap.sh/bi-analyst","nodeKey":"proj-bi-capstone"}'::jsonb, true, true, '["Apply Dashboard Design, Business Metrics, Data Storytelling through a focused Business Intelligence Capstone Project artifact.","Integrate multiple roadmap areas into one coherent case study rather than isolated exercises.","Explain the main design, data, tooling, workflow, or review decisions behind the project.","Validate the result with evidence that another person can inspect.","Document assumptions, limitations, and a concrete follow-up improvement."]'::jsonb, '["The a portfolio-ready Business Intelligence Capstone Project case study and integrated artifact is available for review.","The Business Intelligence Capstone Project scope, setup path, input data or scenario, and expected output are documented.","The main workflow runs or can be inspected through a notebook, repository, dashboard, prototype, report, configuration, or case study.","The case study connects implementation decisions to relevant roadmap skills and explains why alternatives were not chosen.","Validation evidence is included and directly relates to the project brief.","The notes identify trade-offs, limitations, and one next improvement without claiming mastery or job readiness.","The project is packaged so a reviewer can understand the artifact without live mentoring."]'::jsonb),
('proj-bi-portfolio-site', 'ph-portfolio-career', 1501, 'project', NULL, NULL, NULL, 'BI Portfolio Site', 'Capstone project: Create a simple portfolio page with case studies, dashboard screenshots, SQL/Python samples, and project narratives.', 'side', 2, 'advanced', '{"project":true,"projectBrief":"Create a simple portfolio page with case studies, dashboard screenshots, SQL/Python samples, and project narratives.","projectKind":"portfolio_capstone","projectScope":"portfolio_capstone","projectPurpose":"Integrate several roadmap areas into a portfolio-ready case study.","phaseContext":"Portfolio, Interview Readiness, and Capstone","deliverable":"a portfolio-ready BI Portfolio Site case study and integrated artifact","skillsToPractice":["Portfolio Communication"],"suggestedSteps":["Define the BI Portfolio Site scenario and list the specific items to demonstrate: SQL queries, dashboard decisions.","Choose a coherent product or case-study scenario that can integrate the strongest projects from the roadmap.","Define the architecture, data or workflow model, user path, and review evidence before implementation.","Build the core artifact end-to-end with scoped features rather than disconnected demos.","Add validation evidence appropriate to the role, such as tests, metrics, query checks, playtest notes, traces, screenshots, or incident notes.","Prepare a case study explaining decisions, trade-offs, limitations, and what would need further review for real deployment.","Package the repository or artifact so another person can reproduce or inspect the result.","Create a review checklist that connects the artifact to the relevant skills and roadmap segment.","Write a limitation and risk section so the project is presented as reviewable evidence, not a certification claim."],"expectedEvidence":["a portfolio-ready BI Portfolio Site case study and integrated artifact.","README or notes that explain setup, usage, assumptions, and expected output.","Case study page or write-up that connects the artifact to role-relevant decisions and evidence.","Validation evidence such as tests, screenshots, logs, query results, metrics, traces, or review notes.","Short reflection on trade-offs, limitations, and one reasonable next improvement.","Architecture, review checklist, and limitation section suitable for portfolio discussion."],"reviewFocus":["Does the artifact directly match the project brief?","Can another person run, inspect, or review the result from the provided notes?","Are assumptions, limitations, and trade-offs stated clearly?"],"scopeGuardrails":["Keep the implementation focused on the stated project brief.","Prefer a complete small artifact over a broad unfinished system.","Treat completion as reviewable evidence, not a certification claim."],"claimLimit":"Completion creates reviewable project evidence. It does not certify mastery or guarantee job readiness.","evidenceRequired":true,"optionalPractice":true,"milestone":false,"source":"roadmap.sh/bi-analyst","nodeKey":"proj-bi-portfolio-site"}'::jsonb, false, true, '["Apply Portfolio Communication through a focused BI Portfolio Site artifact.","Integrate multiple roadmap areas into one coherent case study rather than isolated exercises.","Explain the main design, data, tooling, workflow, or review decisions behind the project.","Validate the result with evidence that another person can inspect.","Document assumptions, limitations, and a concrete follow-up improvement."]'::jsonb, '["The a portfolio-ready BI Portfolio Site case study and integrated artifact is available for review.","The BI Portfolio Site scope, setup path, input data or scenario, and expected output are documented.","The main workflow runs or can be inspected through a notebook, repository, dashboard, prototype, report, configuration, or case study.","The case study connects implementation decisions to relevant roadmap skills and explains why alternatives were not chosen.","Validation evidence is included and directly relates to the project brief.","The notes identify trade-offs, limitations, and one next improvement without claiming mastery or job readiness.","The project is packaged so a reviewer can understand the artifact without live mentoring."]'::jsonb);
